msg._sql = `SELECT table_catalog, table_schema, table_name FROM "${env.get('AI_INSIGHT_TRINO__CATALOG') || 'fap-iotai-stackable'}".information_schema.tables WHERE table_schema NOT IN ('information_schema','sys','pg_catalog') ORDER BY table_catalog, table_schema, table_name LIMIT 1000`;
msg._shape = 'list';
return msg;

const p = msg.req && msg.req.params || {};
const IDENT_RE = /^[A-Za-z0-9_.-]{1,64}$/;
for (const k of ['catalog','schema','table']) {
  if (p[k] && !IDENT_RE.test(p[k])) {
    msg.statusCode = 400;
    msg.headers = { 'Content-Type': 'application/json' };
    msg.payload = { detail: `invalid ${k}: must match ^[A-Za-z0-9_.-]{1,64}$` };
    return msg;
  }
}
const quote = (v) => '"' + String(v).replace(/"/g, '""') + '"';
if (!p.catalog || !p.schema || !p.table) {
  msg.statusCode = 400;
  msg.headers = { 'Content-Type': 'application/json' };
  msg.payload = { detail: 'catalog, schema, and table are required' };
  return msg;
}
msg._sql = `SELECT column_name, data_type, is_nullable, ordinal_position FROM ${quote(p.catalog)}.information_schema.columns WHERE table_schema = '${p.schema.replace(/'/g, "''")}' AND table_name = '${p.table.replace(/'/g, "''")}' ORDER BY ordinal_position`;
msg._shape = 'describe';
return msg;

// httpsFetch shim — function-node sandbox lacks global fetch. Uses Node stdlib.
function httpsFetch(urlStr, opts = {}) {
  return new Promise((resolve, reject) => {
    let parsed;
    try { parsed = new urlmod.URL(urlStr); }
    catch (e) { return reject(new Error('bad URL: ' + urlStr)); }
    const isHttps = parsed.protocol === 'https:';
    const lib = isHttps ? https : http;
    const body = opts.body;
    const headers = Object.assign({}, opts.headers || {});
    if (body && !headers['Content-Length']) headers['Content-Length'] = Buffer.byteLength(body);
    const req = lib.request({
      method: opts.method || 'GET',
      hostname: parsed.hostname,
      port: parsed.port || (isHttps ? 443 : 80),
      path: parsed.pathname + (parsed.search || ''),
      headers,
      timeout: opts.timeoutMs || 5000,
      rejectUnauthorized: opts.rejectUnauthorized !== false
    }, (res) => {
      let data = '';
      res.on('data', (c) => { data += c; });
      res.on('end', () => resolve({
        ok: res.statusCode >= 200 && res.statusCode < 300,
        status: res.statusCode,
        headers: res.headers,
        text: () => Promise.resolve(data),
        json: () => { try { return Promise.resolve(JSON.parse(data)); } catch (e) { return Promise.reject(e); } }
      }));
    });
    req.on('error', reject);
    req.on('timeout', () => { req.destroy(new Error('timeout')); });
    if (body) req.write(body);
    req.end();
  });
}

const tokenUrl = env.get('AI_INSIGHT_TRINO__OIDC_TOKEN_URL');
const clientId = env.get('AI_INSIGHT_TRINO__OIDC_CLIENT_ID');
const clientSecret = env.get('AI_INSIGHT_TRINO__OIDC_CLIENT_SECRET');
const username = env.get('AI_INSIGHT_TRINO__OIDC_USERNAME');
const password = env.get('AI_INSIGHT_TRINO__OIDC_PASSWORD');
const scope = env.get('AI_INSIGHT_TRINO__OIDC_SCOPE') || 'openid';
const trinoScheme = env.get('AI_INSIGHT_TRINO__HTTP_SCHEME') || 'https';
const trinoHost = env.get('AI_INSIGHT_TRINO__HOST');
const trinoPort = env.get('AI_INSIGHT_TRINO__PORT') || 8443;
const trinoUser = env.get('AI_INSIGHT_TRINO__USER') || 'trino';

// URLSearchParams is not in the function-node sandbox; build the form body manually.
const formEncode = (obj) => Object.entries(obj)
  .filter(([, v]) => v !== undefined && v !== null && v !== '')
  .map(([k, v]) => `${encodeURIComponent(k)}=${encodeURIComponent(v)}`)
  .join('&');

async function getToken() {
  const body = formEncode({ grant_type: 'password', client_id: clientId, client_secret: clientSecret, username, password, scope });
  const res = await httpsFetch(tokenUrl, { method: 'POST', headers: { 'Content-Type': 'application/x-www-form-urlencoded' }, body, /* known: pod's Alpine image lacks LE CA chain */ rejectUnauthorized: false });
  if (!res.ok) throw new Error(`token grant failed: ${res.status}`);
  return (await res.json()).access_token;
}

async function runQuery(sql, token) {
  const base = `${trinoScheme}://${trinoHost}:${trinoPort}`;
  const headers = { 'Authorization': `Bearer ${token}`, 'X-Trino-User': trinoUser, 'Content-Type': 'text/plain' };
  let res = await httpsFetch(`${base}/v1/statement`, { method: 'POST', headers, body: sql, rejectUnauthorized: false });
  if (!res.ok) throw new Error(`POST /v1/statement failed: ${res.status}`);
  let body = await res.json();
  let columns = body.columns || null;
  const rows = body.data ? [...body.data] : [];
  while (body.nextUri) {
    res = await httpsFetch(body.nextUri, { headers, rejectUnauthorized: false });
    if (!res.ok) throw new Error(`nextUri failed: ${res.status}`);
    body = await res.json();
    if (body.columns) columns = body.columns;
    if (body.data) rows.push(...body.data);
  }
  return { columns, rows };
}

try {
  if (msg.statusCode === 400) return msg;  // already validated
  if (!msg._sql) { msg.statusCode = 400; msg.headers = { 'Content-Type': 'application/json' }; msg.payload = { detail: 'no SQL prepared' }; return msg; }
  const token = await getToken();
  const { columns, rows } = await runQuery(msg._sql, token);
  let payload;
  if (msg._shape === 'list') {
    payload = { tables: rows.map(r => ({ catalog: r[0], schema: r[1], table: r[2] })), count: rows.length };
  } else {
    payload = {
      columns: rows.map(r => ({ name: r[0], type: r[1], nullable: r[2] === 'YES', position: r[3] })),
      count: rows.length
    };
  }
  msg.statusCode = 200;
  msg.headers = { 'Content-Type': 'application/json', 'Cache-Control': 'no-store' };
  msg.payload = payload;
} catch (e) {
  msg.statusCode = 502;
  msg.headers = { 'Content-Type': 'application/json' };
  node.warn('Trino query failed: ' + String(e.message || e));
  msg.payload = { detail: 'Trino query failed' };
}
return msg;
